# In a real scenario, this would be your actual backend service
BACKEND_SERVICE_BASE_URL = "http://localhost:5001" 

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'])
def gateway(path):
    auth_header = request.headers.get('Authorization')

    if not auth_header:
        return jsonify({"message": "Authorization header missing"}), 401

    try:
        token_type, token = auth_header.split(None, 1)
        if token_type.lower() != 'bearer':
            return jsonify({"message": "Unsupported authorization type"}), 401
    except ValueError:
        return jsonify({"message": "Invalid Authorization header format"}), 401

    try:
        # For development speed, verify=False is used.
        # In a production environment, you MUST set verify=True and provide
        # the correct secret/public key and algorithms.
        decoded_token = jwt.decode(token, options={"verify_signature": False})
        user_claims = decoded_token
    except jwt.exceptions.DecodeError:
        return jsonify({"message": "Invalid token"}), 401
    except Exception as e:
        return jsonify({"message": f"Token decoding error: {str(e)}"}), 500

    # Prepare headers for the backend service
    # Forward original headers, but add/override with user_claims
    backend_headers = {k: v for k, v in request.headers.items()}
    
    # Example: Forward user claims as custom headers or a JSON string
    # You might want to prefix these to avoid conflicts, e.g., 'X-User-ID', 'X-User-Roles'
    backend_headers['X-User-Claims'] = jsonify(user_claims).get_data(as_text=True)
    
    # Remove Authorization header before forwarding to backend if the backend doesn't need it
    # and you've already processed the claims
    if 'Authorization' in backend_headers:
        del backend_headers['Authorization']

    # Construct the full URL for the backend service
    backend_url = f"{BACKEND_SERVICE_BASE_URL}/{path}"

    try:
        # Make the request to the backend service
        response = requests.request(
            method=request.method,
            url=backend_url,
            headers=backend_headers,
            data=request.get_data(),  # Forward request body
            params=request.args,      # Forward query parameters
            allow_redirects=False,
            stream=True # Stream response to handle large files efficiently
        )

        # Prepare the response to send back to the client
        excluded_headers = ['content-encoding', 'content-length', 'transfer-encoding', 'connection']
        response_headers = [
            (name, value) for name, value in response.raw.headers.items()
            if name.lower() not in excluded_headers
        ]

        return app.response_class(
            response=response.content,
            status=response.status_code,
            headers=response_headers
        )

    except requests.exceptions.ConnectionError:
        return jsonify({"message": "Backend service is unavailable"}), 503
    except Exception as e:
        return jsonify({"message": f"Error forwarding request to backend: {str(e)}"}), 500

